</code></pre> <pre><code>import time
from repod import ConnectionListener

class MyClient(ConnectionListener):
    def Network_connected(self, data: dict) -&gt; None:
        print("connected!")

    def Network_message(self, data: dict) -&gt; None:
        print(data)

client = MyClient()
client.connect("localhost", 5071)

while True:
    client.pump()
    time.sleep(0.01)
